const startMs = $('Start Timer').first().json.startMs;
const checks = [];
let allPassed = true;

try {
  const r = $('Check AI Service').first().json;
  const ok = !!(r?.status === 'ok' || r?.status === 'healthy' || r?.uptime);
  if (!ok) allPassed = false;
  checks.push({ name: 'ai-service', ok, detail: r?.status ?? JSON.stringify(r).slice(0, 100) });
} catch(e) {
  allPassed = false;
  checks.push({ name: 'ai-service', ok: false, detail: e.message });
}

try {
  const r = $('Check Qdrant').first().json;
  const hasCollections = Array.isArray(r?.result?.collections) || Array.isArray(r?.collections);
  const ok = !!(hasCollections || r?.title || r?.result === 'ok' || r?.status === 'ok');
  if (!ok) allPassed = false;
  const detail = hasCollections
    ? `collections: ${(r?.result?.collections || r?.collections || []).length}`
    : (r?.title ?? r?.result ?? JSON.stringify(r).slice(0, 100));
  checks.push({ name: 'qdrant', ok, detail });
} catch(e) {
  allPassed = false;
  checks.push({ name: 'qdrant', ok: false, detail: e.message });
}

const durationMs = Date.now() - startMs;
return [{ json: {
  passed: allPassed,
  step: 'AI',
  statusCode: allPassed ? 200 : 503,
  details: checks.map(c => `${c.name}: ${c.ok ? 'OK' : 'FAIL'}`).join(' | '),
  durationMs,
  checks
} }];
